mapper.select:
SELECT thp.*, tcd.minor_nm AS dataTypeNm, tsf.file_id, esg.fn_getapprovalstatus('PLC', thp.write_year || thp.doc_no) as approval_status, COALESCE(COUNT(thps.doc_seq),0) as workerSuggestionCnt FROM esg.tb_hse_policy thp LEFT JOIN esg.tb_common_d tcd ON tcd.major_cd = 'C0013' AND thp.data_type = tcd.minor_cd LEFT JOIN esg.tb_sys_file tsf ON thp.write_year||thp.doc_no = tsf.target_id AND tsf.target_type = thp.data_type LEFT JOIN esg.tb_hse_policy_suggestion thps ON thps.comp_id = thp.comp_id AND thps.doc_type = thp.doc_type AND thps.write_year = thp.write_year AND thps.doc_no = thp.doc_no AND thps.use_yn = 'Y' WHERE thp.comp_id = #{compId}
AND thp.confirm_yn = #{searchText}
GROUP BY thp.comp_id, thp.write_year, thp.doc_type, thp.doc_no, tcd.minor_nm, tsf.file_id ORDER BY thp.use_yn DESC, thp.write_year desc, thp.created_at desc

SELECT thp.*,
    tsf.file_id
FROM esg.tb_hse_policy thp
LEFT JOIN esg.tb_sys_file tsf
    ON thp.write_year||thp.doc_no = tsf.target_id
    AND thp.doc_type = tsf.target_type
WHERE thp.comp_id = #{compId}
   AND thp.write_year = #{writeYear}
   AND thp.doc_type = #{docType}
   AND thp.doc_no = #{docNo}
LIMIT 1;

SELECT tdhp.*,
    (SELECT tci.comp_nm
        FROM esg.tb_company_info tci
        WHERE tci.comp_id = #{compId}
    )
FROM dataset.tb_dataset_hse_policy tdhp

mapper.insert:
SELECT LPAD((COALESCE(MAX(doc_no::INTEGER), 0) + 1)::TEXT, 5, '0') AS docNo FROM esg.tb_hse_policy WHERE write_year = #{writeYear} AND doc_type = #{docType}
INSERT INTO esg.tb_hse_policy ( write_year, doc_type, doc_no, data_type, content_header, content_body, content_footer, use_yn, created_at, created_by, comp_id, confirm_yn, confirm_dt ) VALUES (
#{writeYear}, #{docType}, #{docNo}, #{dataType}, #{contentHeader}, #{contentBody}, #{contentFooter}, #{useYn}, now(), #{createdBy}, #{compId}, 'N', null )

mapper.update:
UPDATE esg.tb_hse_policy
SET
    use_yn = #{useYn},
    content_header = #{contentHeader},
    content_body = #{contentBody},
    content_footer = #{contentFooter},
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE comp_id = #{compId}
    AND write_year = #{writeYear}
    AND doc_type = #{docType}
    AND doc_no = #{docNo}

UPDATE esg.tb_hse_policy
SET
    confirm_yn = #{confirmYn}

    , confirm_dt = now()


    , confirm_dt = null

WHERE comp_id = #{compId}
    AND write_year = #{writeYear}
    AND doc_type = #{docType}
    AND doc_no = #{docNo}

UPDATE esg.tb_hse_policy
SET
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE comp_id = #{compId}
    AND write_year = #{writeYear}
    AND doc_type = #{docType}
    AND doc_no = #{docNo}

mapper.select:
SELECT thps.*
    , tci.comp_nm
    , thi.hr_nm
    , jbrp.jbrp_nm
FROM esg.tb_hse_policy_suggestion thps
LEFT JOIN esg.tb_company_info tci
    ON tci.comp_id = thps.comp_id
LEFT JOIN esg.tb_hr_info thi
    ON thi.hr_id = thps.hr_id
left join esg.tb_hr_info_jbrp jbrp
    on jbrp.jbrp_id = thi.jbrp and jbrp.comp_id = #{compId}
WHERE thps.comp_id = #{compId}
    AND thps.write_year = #{writeYear}
    AND thps.doc_type = #{docType}
    AND thps.doc_no = #{docNo}

    AND thi.user_id = #{userId}


    AND (
        TO_TIMESTAMP(#{searchTo}|| '2359', 'YYYYMMDDHH24MI') >= COALESCE(thps.updated_at, thps.created_at)
        AND COALESCE(thps.updated_at, thps.created_at) >= TO_TIMESTAMP(#{searchFrom}, 'YYYYMMDDHH24MI')
      )

ORDER BY thps.created_at DESC, thps.updated_at DESC

